const rateLimit = require('express-rate-limit');
const { redis } = require('../config/redis');

// 导入 ipKeyGenerator 助手函数
const { ipKeyGenerator } = require('express-rate-limit');

// 自定义 Redis 存储适配器 - 适配 Upstash Redis
class RedisStore {
  constructor() {
    this.redis = redis;
  }

  async increment(key) {
    try {
      const now = Date.now();
      const windowMs = 60000; // 1分钟窗口
      
      // 使用 Upstash Redis 兼容的方式
      const currentCount = await this.redis.get(key);
      const count = (currentCount ? parseInt(currentCount) : 0) + 1;
      
      // 设置新的计数和过期时间
      await this.redis.set(key, count.toString(), { ex: Math.ceil(windowMs / 1000) });
      
      return {
        totalHits: count,
        resetTime: new Date(now + windowMs)
      };
    } catch (error) {
      console.error('Redis rate limit error:', error);
      // 降级到内存存储
      return this.fallbackIncrement(key);
    }
  }

  async decrement(key) {
    try {
      const currentCount = await this.redis.get(key);
      if (currentCount) {
        const newCount = Math.max(0, parseInt(currentCount) - 1);
        await this.redis.set(key, newCount.toString());
      }
    } catch (error) {
      console.error('Redis decrement error:', error);
    }
  }

  async resetKey(key) {
    try {
      await this.redis.del(key);
    } catch (error) {
      console.error('Redis reset error:', error);
    }
  }

  // 降级到内存存储
  fallbackIncrement(key) {
    if (!this.memoryStore) {
      this.memoryStore = new Map();
    }
    
    const now = Date.now();
    const windowMs = 60000;
    
    if (!this.memoryStore.has(key)) {
      this.memoryStore.set(key, { count: 0, resetTime: now + windowMs });
    }
    
    const entry = this.memoryStore.get(key);
    if (now > entry.resetTime) {
      entry.count = 0;
      entry.resetTime = now + windowMs;
    }
    
    entry.count++;
    
    return {
      totalHits: entry.count,
      resetTime: new Date(entry.resetTime)
    };
  }
}

// 安全的 key 生成器 - 使用 ipKeyGenerator 助手函数
function safeKeyGenerator(req) {
  try {
    // 优先使用用户ID
    if (req.user && req.user.id) {
      return `user:${req.user.id}`;
    }
    
    // 否则使用 ipKeyGenerator 助手函数处理 IP 地址
    return `ip:${ipKeyGenerator(req)}`;
  } catch (error) {
    console.error('Key generator error:', error);
    return 'unknown';
  }
}

// 通用限流配置
const createRateLimiter = (windowMs, max, message = '请求过于频繁，请稍后再试') => {
  return rateLimit({
    store: new RedisStore(),
    windowMs,
    max,
    message: {
      success: false,
      message,
      code: 'RATE_LIMIT_EXCEEDED'
    },
    standardHeaders: true,
    legacyHeaders: false,
    keyGenerator: safeKeyGenerator,
    skip: (req) => {
      // 跳过健康检查等接口
      return req.path === '/api/health';
    }
  });
};

// 导出限流器
module.exports = {
  createRateLimiter,
  // 预定义的限流器
  authLimiter: createRateLimiter(15 * 60 * 1000, 5, '登录尝试次数过多，请15分钟后再试'), // 15分钟5次
  registerLimiter: createRateLimiter(60 * 60 * 1000, 3, '注册尝试次数过多，请1小时后再试'), // 1小时3次
  apiLimiter: createRateLimiter(60 * 1000, 100, 'API请求过于频繁，请稍后再试'), // 1分钟100次
  pixelLimiter: createRateLimiter(60 * 1000, 50, '像素绘制过于频繁，请稍后再试'), // 1分钟50次
  chatLimiter: createRateLimiter(10 * 1000, 10, '聊天消息发送过于频繁，请稍后再试'), // 10秒10次
  uploadLimiter: createRateLimiter(60 * 1000, 5, '文件上传过于频繁，请稍后再试'), // 1分钟5次
  adminLimiter: createRateLimiter(60 * 1000, 1000, '管理员操作过于频繁'), // 管理员限制较宽松
};
